CropsConfig = {}
CropsConfig.crops = {}

function CropsConfig:init(config)
    for i, crop in pairs(config) do
        local item = {}
        item.id = tonumber(crop.id)
        item.itemId = tonumber(crop.itemId)
        item.blockId = tonumber(crop.blockId)
        item.drop_itemid = tonumber(crop.drop_itemid)
        self.crops[i] = item
    end
end

function CropsConfig:checkCropsByItemId(blockId)
    for i, k in pairs(self.crops) do
        if k.itemId == blockId then
            return true
        end
    end
    return false
end

function CropsConfig:checkCropsByBlockId(blockId)
    for i, k in pairs(self.crops) do
        if k.blockId == blockId then
            return true
        end
    end
    return false
end

function CropsConfig:checkDropByItemid(itemId)
    for i, k in pairs(self.crops) do
        if k.drop_itemid == itemId then
            return true
        end
    end
    return false
end
